// Generate personalized water reminders
const userData = $input.all();
const reminders = [];

for (const user of userData) {
  const data = user.json;
  const percentage = Math.round((data.water_intake / data.water_goal) * 100);
  const remaining = data.water_goal - data.water_intake;

  let message = '';
  let emoji = '💧';
  let motivation = '';

  if (data.status === 'behind') {
    message = `Time to hydrate, ${data.name}!`;
    motivation = 'You\'re behind on your water goal today. Let\'s catch up!';
    emoji = '⚠️';
  } else if (data.status === 'on_track') {
    message = `Great hydration progress, ${data.name}!`;
    motivation = 'You\'re doing well! Keep it up to reach your goal.';
    emoji = '👍';
  }

  reminders.push({
    user_id: data.id,
    email: data.email,
    name: data.name,
    water_intake: data.water_intake,
    water_goal: data.water_goal,
    percentage: percentage,
    remaining_ml: remaining,
    remaining_glasses: Math.ceil(remaining / 250),
    status: data.status,
    message: message,
    motivation: motivation,
    emoji: emoji,
    hydration_tips: [
      'Start your day with a glass of water',
      'Keep a water bottle visible at your desk',
      'Set phone reminders every hour',
      'Drink water before each meal',
      'Flavor water with lemon or cucumber'
    ],
    benefits: [
      'Boosts energy and brain function',
      'Helps maintain body temperature',
      'Supports kidney function',
      'Improves skin health',
      'Aids digestion and metabolism'
    ]
  });
}

return reminders.map(reminder => ({ json: reminder }));
